export function fuzzyEquals(query, text, caseSensitive = false) {
    const textLength = text.length, queryLength = query.length;
    if (queryLength > textLength) {
        return false;
    }
    else {
        return internalFuzzyEquals(caseSensitive !== true ? query.toLowerCase() : query, queryLength, caseSensitive !== true ? text.toLowerCase() : text, textLength);
    }
}
export function internalFuzzyEquals(query, queryLength, text, textLength) {
    let i = 0, j = 0;
    outer: while (i < queryLength) {
        const ch = query.charAt(i++);
        while (j < textLength) {
            if (text.charAt(j++) === ch) {
                continue outer;
            }
        }
        return false;
    }
    return true;
}
